/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;

    // Step 1: Find the peak index P
    // P is the index where the array stops strictly increasing.
    let peakIndex = 0;
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            peakIndex = i;
        } else {
            // Since it's strictly unimodal, the drop means the peak was at i-1.
            break;
        }
    }

    // Step 2: Calculate sums

    // Sum of the increasing part (0 to P, inclusive)
    let sumInc = 0;
    for (let i = 0; i <= peakIndex; i++) {
        sumInc += nums[i];
    }

    // Sum of the decreasing part (P to N-1, inclusive)
    let sumDec = 0;
    for (let i = peakIndex; i < n; i++) {
        sumDec += nums[i];
    }

    // Step 3: Compare and return
    if (sumInc > sumDec) {
        // Increasing part is larger
        return 0;
    } else if (sumDec > sumInc) {
        // Decreasing part is larger
        return 1;
    } else {
        // Equal
        return -1;
    }
}

