        // For N=1 or N=2, the definition of unimodal might be ambiguous regarding strictness,
        // but based on constraints N >= 3.
    }

    // Step 1: Find the peak index P
    let peakIndex = 0;
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            peakIndex = i;
        } else {
            // Found the drop or plateau (but it's strictly unimodal, so it must be a drop)
            // The peak is the previous index.
            break;
        }
    }

    // Step 2: Calculate sums

    // Sum of the increasing part (0 to P, inclusive)
    let sumInc = 0;
    for (let i = 0; i <= peakIndex; i++) {
        sumInc += nums[i];
    }

    // Sum of the decreasing part (P to N-1, inclusive)
    let sumDec = 0;
    for (let i = peakIndex; i < n; i++) {
        sumDec += nums[i];
    }

    // Step 3: Compare and return
    if (sumInc > sumDec) {
        return 0;
    } else if (sumDec > sumInc) {
        return 1;
    } else {
